import psycopg2
from psycopg2 import sql, extensions

def connect():
    conn = None
    try:
        conn = psycopg2.connect(
            database="your_database",
            user="your_username",
            password="your_password",
            host="localhost",  # or your ip
            port="5432",
        )
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)
    return conn

def search_users(**kwargs):
    conn = connect()
    cur = conn.cursor()
    
    query = "SELECT * FROM users WHERE"
    
    if kwargs:
        conditions = []
        
        for key, val in kwargs.items():
            if key == 'role':
                role_val = '%' + val + '%'
                conditions.append(sql.SQL("{} LIKE %s").format(sql.Identifier(key)), role_val)
                
            elif key == 'status':
                status_val = '%' + val + '%'
                conditions.append(sql.SQL("{} LIKE %s").format(sql.Identifier(key)), status_val)
            
            else:
                conditions.append(sql.SQL("{}=%s").format(sql.Identifier(key)), val)
        
        query += ' AND '.join([str(c[0]) for c in conditions])
    
    cur.execute(query, [c[1] for c in conditions])
    
    rows = cur.fetchall()
    return rows